-- ════════════════════════════════════════════════════════════════════
-- Port-to-port routes (ECDIS voyage plans) — the stored geometry + distance the
-- map draws exact (solid + 'ECDIS' tag) and the distance matrix is computed from.
-- Source: ArabShipBroker_MASTER_Port_Routes.xlsx (20 plans). Symmetric — reverse
-- is the same line. Grow this table over time: each added pair draws exact
-- automatically. (The map engine lib/portal/routeGeometry.ts currently bundles
-- this same set for a standalone client; point it at this table to source live.)
-- Append-only · world-readable reference (no PII).
-- ════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS public.port_routes (
  id         uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  locode_a   text NOT NULL,
  locode_b   text NOT NULL,
  total_nm   numeric NOT NULL,
  waypoints  jsonb   NOT NULL,        -- ordered [[lat,lon], …]
  created_at timestamptz NOT NULL DEFAULT now(),
  UNIQUE (locode_a, locode_b)
);
ALTER TABLE public.port_routes ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "port_routes read" ON public.port_routes;
CREATE POLICY "port_routes read" ON public.port_routes FOR SELECT TO anon, authenticated USING (true);

